/* Fix the tooltip positioning:
   - The wrapper should be the positioning context
   - The tooltip should be positioned above the button
   - Center the tooltip horizontally */
.btn-wrapper {
  position: static; /* wrong */
  display: inline-block;
  margin: 60px;
}
.btn {
  padding: 8px 16px;
  cursor: pointer;
}
.tooltip {
  position: absolute; /* correct, but parent is wrong */
  bottom: -30px; /* should be above, not below */
  left: 50%;
  transform: translateX(-50%);
  background-color: #333;
  color: white;
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 12px;
  white-space: nowrap;
}

